<html>
  <head>
    %@LW_pgstart@@
    <title>%@LW_PField_s_prnFile@%</title>
    <style>
      /* table, th, td {
        border: 1px solid black;
      } */

      body {
        background-color: #fff;
        font-family: sans-serif;
        padding-left: 30px;
        padding-top: 30px;
        padding-right: 30px;
        padding-bottom: 30px;
        width: 840px;
        height: 850px;
      }

      table {
        border-collapse: collapse;
        width: 100%;
        margin-bottom: 20px;
      }

      th {
        height: 25px;
        font-weight: bold;
      }

      td {
        word-wrap: break-word;
      }

      th, td {
        font-size: 14px;
      }

      #head table, #head td, #head th {
        border: none !important;
      }

      @media print and (min-resolution: 144dpi) {
        .no-print, .no-print * {
          display: none !important;
        }
      }

      .bt {
        border-top: 1px solid;
      }

      .br {
        border-right: 1px solid;
      }

      .bb {
        border-bottom: 1px solid;
      }

      .bl {
        border-left: 1px solid;
      }

      .ba {
        border: 1px solid;
      }

      .p {
        padding: 10px 5px;
      }

      .bold {
        font-weight: bold;
      }
    </style>

    <script defer>
	  function reindexNorut(norut) {
	    const e = norut.querySelectorAll('.norut');
	    let index = 1;
	    e.forEach(td => {
	      td.textContent = `${index}`;
	      index += 1;
	    });
	  }

      function capitalizeWords(str) {
        return str
          .toLowerCase()
          .split(' ')
          .map(word => word.charAt(0).toUpperCase() + word.slice(1))
          .join(' ');
      }

      document.addEventListener('DOMContentLoaded', function () {
        reindexNorut(document);

        const tdElements = document.querySelectorAll('.bilang');
        tdElements.forEach(td => {
          td.textContent = capitalizeWords(td.textContent.trim());
        });

        const elements = document.querySelectorAll('.angka');
        elements.forEach(td => {
          const num = parseFloat(td.textContent.replace(/,/g, ''));
          if (!isNaN(num)) {
            td.textContent = num.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
          }
        });        
      });
    </script>

  </head>

<body text="#000" style="background-color:#EEFBFF">
  LW_pgstart@%
  %@LW_prowno_0@@
  <button class="no-print" onclick="window.print()">Print</button>

  <div style="display: flex; justify-content: center; margin-bottom: 13px;">
    <div style="width: 10%">
      <img src="../menu/Lpx/sinter_logo.png" style="width: 67px; height: 67px;"/>
    </div>
    <div style="width: 40%">
      <p style="margin: 0;">%@LW_PField_TableDS(gl820a,tb_descr,"0")@%</p>
