      <p style="margin: 2px; font-size: 14px;">%@LW_PField_TableDS(gl820a,tb_adr3,"0")@%</p>
    </div>
    <div style="width: 50%; text-align: right; font-size: 14px;">
      <p style="margin: 0 0 4px 0;">%@LW_PField_fa_Name@%</p>
