  	<table>
      <tr>
      	<td style="width: 65px;">Invoice No.</td>
      	<td style="width: 5px;">:</td>
      	<td>%@LW_PField_fa_nofak@%</td>
      </tr>
      <tr>
      	<td>Invoice Dt.</td>
      	<td>:</td>
      	<td>%@LW_PField_dvBilang(fa_dtfak)@%</td>
      </tr>
    </table>
  </div>

  <table>
    <thead>
      <tr class="bb">
        <th class="p" style="width: 15px;">No</th>
        <th class="p" style="text-align: left;">Kode</th>
        <th class="p" style="text-align: left;">No.Part</th>
        <th class="p" style="text-align: left;">Nama Barang</th>
        <th class="p" style="text-align: left;">Deskripsi</th>
        <th class="p" style="text-align: right;">Qty</th>
        <th class="p" style="text-align: right;">Available</th>
        <th class="p" style="text-align: left;">Sat</th>
      </tr>
    </thead>
    LW_prowno_0@%
    <tbody>
      %@LW_prowno_10@@

      <tr style="vertical-align: text-top;">
        <td class="p norut" style="text-align: center;"></td>
        <td class="p">%@LW_PField_fa_itemid@%</td>
        <td class="p">%@LW_PField_TableDs(ic010a,im_partno,fa_itemid)@%</td>
