        <td class="p" style="text-align: left;">%@LW_PField_fa_qtx@N/2,N@%</td>
        <td class="p" style="text-align: left;">%@LW_PField_TableDs(ic011a,im_qty_a+im_qty_m-im_qty_k,fa_itemid+fa_whs)@%</td>      
        <td class="p">%@LW_PField_fa_unit@%</td>
