      LW_prowno_10@%
      %@LW_prowno_299@@
      <tr>
        <td colspan="8" style="padding-top: 10px;">Note:</td>
      </tr> 
      <tr><td colspan="8" >Ekspedisi: %@LW_PField_fa_descr@%</td></tr>
      <tr><td colspan="8" >Keterangan:</td></tr>
      <tr><td colspan="8" >%@LW_PField_fa_remark@%</td></tr>
      <tr><td colspan="8" >%@LW_PField_fa_remark2@%</td></tr>
      <tr><td colspan="8" >%@LW_PField_fa_remark3@%</td></tr>
    </tbody>
  </table>
  LW_prowno_299@%
</body>
%@LW_pgend@@
LW_pgend@%
</html>

